/**
 * @summary Search memories
 */
export const getSearchMemoriesUrl = (params: SearchMemoriesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/memories/search?${stringifiedParams}`
    : `/api/memories/search`;
};

export const searchMemories = async (
  params: SearchMemoriesParams,
  options?: RequestInit,
): Promise<MemoriesResponse> => {
  return customFetch<MemoriesResponse>(getSearchMemoriesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getSearchMemoriesQueryKey = (params?: SearchMemoriesParams) => {
  return [`/api/memories/search`, ...(params ? [params] : [])] as const;
};

export const getSearchMemoriesQueryOptions = <
  TData = Awaited<ReturnType<typeof searchMemories>>,
  TError = ErrorType<unknown>,
>(
  params: SearchMemoriesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchMemories>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getSearchMemoriesQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof searchMemories>>> = ({
    signal,
  }) => searchMemories(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof searchMemories>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type SearchMemoriesQueryResult = NonNullable<
  Awaited<ReturnType<typeof searchMemories>>
>;
export type SearchMemoriesQueryError = ErrorType<unknown>;

/**
 * @summary Search memories
 */

export function useSearchMemories<
  TData = Awaited<ReturnType<typeof searchMemories>>,
  TError = ErrorType<unknown>,
>(
  params: SearchMemoriesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchMemories>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getSearchMemoriesQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
